func compareEncoding(a, b Encoding) int {
	lhs, rhs := a.Weight, b.Weight

	if lhs == nil && rhs == nil {
		return 0
	}

	if lhs == nil && *rhs == 0 {
		return -1
	}

	if lhs == nil {
		return 1
	}

	if rhs == nil && *lhs == 0 {
		return 1
	}

	if rhs == nil {
		return -1
	}

	if *lhs < *rhs {
		return 1
	}

	if *lhs > *rhs {
		return -1
	}

	return 0
}
